// Score Calculator — fix the type bug

const score1 = "88";   // comes in as a string
const score2 = "92";
const score3 = "75";

// BUG: score1 + score2 + score3 concatenates strings!
// Fix: convert each to a number first using Number()
const s1 = Number(score1);
// Your code: convert score2 and score3

// Compute total and average
const total   = s1 + s2 + s3;
const average = (total / 3).toFixed(1);

console.log("Total:",   total);
console.log("Average:", average);

exercise.solutionCode:
const score1 = "88";
const score2 = "92";
const score3 = "75";

const s1 = Number(score1);
const s2 = Number(score2);
const s3 = Number(score3);

const total   = s1 + s2 + s3;
const average = (total / 3).toFixed(1);

console.log("Total:",   total);
console.log("Average:", average);
